import React from "react";
import Image from "next/image";
import { IoMdShareAlt } from "react-icons/io";
import Link from "next/link";
import { getCategories } from "@/api_call/api";

export default async function Hero() {
 const catRes = await getCategories({limit:5,is_home:true,status:true})
 const categories = catRes?.data;
  return (
    <div className="bg-gray-200">
      <div className="flex flex-col md:flex-row gap-4 md:gap-5 py-4 md:py-5 px-4 md:px-0 max-w-7xl mx-auto">
        {/* Category sidebar - hidden on mobile, shown on md+ */}
        <div className="hidden md:block bg-white p-4 md:p-6 md:w-56 lg:w-64 shadow-xl rounded-2xl flex-shrink-0">
          <h1 className="text-[#253D4E] text-xl md:text-2xl">Category</h1>
          <ul className="mt-2">
            {categories.map((items, index) => {
              return (
                <Link key={index} href={"/category"}>
                  <li className="flex border border-gray-300 py-2 px-2 rounded-xl justify-between my-4 md:my-5 items-center gap-4">
                    <div className="flex justify-between items-center gap-3">
                      <img
                        src={`http://localhost:5000/category/${items.image}`}
                        width={20}
                        height={20}
                        alt={items.name}
                      />
                      <span className="text-sm">{items.name}</span>
                    </div>
                  </li>
                </Link>
              );
            })}
          </ul>
        </div>

        {/* Hero banner */}
        <div className="relative w-full h-[220px] sm:h-[300px] md:h-[380px] lg:h-[456px] flex-1">
          <img
            src="/hero.png"
            alt=""
            className="w-full h-full object-cover rounded-2xl md:rounded-3xl"
          />
          <div className="absolute top-0 left-0 px-6 sm:px-10 md:px-14 lg:px-20 py-5 md:py-8 lg:py-10 leading-tight">
            <div className="text-2xl sm:text-3xl md:text-4xl lg:text-[60px] xl:text-[72px] font-bold text-white">
              Don&apos;t miss amazing <br className="hidden sm:block" /> grocery deals
            </div>
            <p className="text-xs sm:text-sm md:text-base lg:text-xl py-3 md:py-6 lg:py-10 font-semibold text-white font-serif">
              Sign up for the daily newsletter
            </p>
            <div className="flex border w-fit items-center rounded-full text-white border-gray-400 bg-transparent ps-3 md:ps-4">
              <div className="flex items-center gap-2 md:gap-3 pe-3 md:pe-5">
                <div className="text-base md:text-xl">
                  <IoMdShareAlt />
                </div>
                <div className="text-xs md:text-sm">Your email address</div>
              </div>
              <div className="py-2 md:py-4 px-4 md:px-8 rounded-full bg-sky-400 text-xs md:text-sm">Subscribe</div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
