import React from "react";
import Link from "next/link";
import { getCategories } from "@/api_call/api";
export default async function Topcategories() {
  const category_res = await getCategories({is_top:true,status:true})
  const categories = category_res?.data;
  const imagePath = category_res?.meta?.imagebaseurl;
  console.log(category_res)
  return (
    <div className="flex-1 bg-white rounded-3xl shadow-md p-4 md:p-6">
      <h1 className="text-lg font-bold text-black mb-4 md:mb-6">
        TOP CATEGORIES
      </h1>
  
      <div className="grid grid-cols-3 sm:grid-cols-4 gap-4 md:gap-6">
        {categories.map((item, index) => {
          return (
            <div
              key={index}
              className="flex flex-col items-center text-center"
            >
                <img
                  src={`http://localhost:5000/category/${item.image}`}
                  alt="category"
                  className="w-12 h-12 md:w-16 md:h-16 object-contain rounded-xl"
                />
  
              <div
                className="mt-2 text-xs md:text-sm font-medium hover:bg-gray-100 px-2 py-1 rounded-xl transition"
              >
                {item.name}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
